import axios from 'axios';

/**
 * 端末情報取得API
 * @param {number|string} termId 端末ID
 * @returns {?object} レスポンス情報(端末情報)
 */
export async function getTerminalAPI(termId) {
  try {
    const url = `/api/Terminals/${termId}`;
    return axios.get(url);
  } catch (error) {
    console.error('getTerminalAPI', error);
  }
}

/**
 * 端末登録API
 * @param {number|string} termId 端末ID
 * @param {string} serverUrl サーバURL
 * @returns {?object} レスポンス情報(端末情報)
 */
export async function postTerminalAPI(termId, serverUrl) {
  try {
    const url = serverUrl + '/api/Terminals';
    const headers = { 'Content-Type': 'application/json' };
    return axios.post(url, { terminalId: termId.toString() }, { headers: headers });
  } catch (error) {
    console.error('postTerminalAPI', error);
  }
}

