axios.interceptors.request.use(function (config) {
  if (typeof config.params === 'undefined') {
    config.params = {};
  }
  if (typeof config.params === 'object') {
    if (typeof URLSearchParams === 'function' && config.params instanceof URLSearchParams)
      config.params.append('_', Date.now());
    else config.params._ = Date.now();
  }
  return config;
});

axios.interceptors.response.use(
  function (response) {
    // 成功時の処理
    return response;
  },
  function (error) {
    // 失敗時の処理
    switch (error.response?.status) {
      case (400, 401, 403, 404):
        console.log(`APIサーバ接続に失敗しました(${error.response?.status})`);
        break;
      case 500:
        console.log('APIサーバ処理に失敗しました(500)');
        break;
      default:
        console.log(`APIサーバで不明なエラーが発生しました(${error.response?.status})`);
        break;
    }
    console.log(error);
    return Promise.reject(error);
  }
);
